UPDATE app_user
SET display_name = #{displayName},
    cpu_think_speed = #{cpuThinkSpeed}
WHERE id = #{id}

UPDATE app_user
SET recycle_crystal = recycle_crystal - #{amount}
WHERE id = #{id} AND COALESCE(recycle_crystal, 0) >= #{amount}

UPDATE app_user
SET selected_epithet_upper_id = #{upperId},
    selected_epithet_lower_id = #{lowerId}
WHERE id = #{id}
